using Microsoft.AspNetCore.Authorization;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        // GET all shipments (dispatchers only)
        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (
            ApplicationDbContext db,
            string? status,
            string? search) =>
        {
            var query = db.Shipments.AsQueryable();

            if (Enum.TryParse<ShipmentStatus>(status, true, out var statusFilter))
                query = query.Where(s => s.Status == statusFilter);

            if (!string.IsNullOrWhiteSpace(search))
                query = query.Where(s =>
                    s.TrackingNumber.Contains(search) ||
                    s.Destination.Contains(search) ||
                    s.RecipientName.Contains(search));

            var shipments = await query
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => s.ToDto())
                .ToListAsync();

            return Results.Ok(shipments);
        });

        // GET single shipment by tracking number (public for customer tracking)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            return shipment is null
                ? Results.NotFound(new { message = "Shipment not found" })
                : Results.Ok(shipment.ToDto());
        });

        // PUT update shipment status (dispatchers only)
        group.MapPut("/{id:int}/status", [Authorize(Roles = "Dispatcher")] async (
            int id,
            UpdateShipmentStatusRequest request,
            ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = request.NewStatus;

            if (request.NewStatus == ShipmentStatus.Delivered)
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(shipment.ToDto());
        });

        // POST create a new shipment (dispatchers only)
        group.MapPost("/", [Authorize(Roles = "Dispatcher")] async (
            ShipmentDto dto,
            ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = dto.TrackingNumber,
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = dto.Status,
                ShippedDate = dto.ShippedDate,
                EstimatedDelivery = dto.EstimatedDelivery,
                RecipientName = dto.RecipientName,
                CarrierName = dto.CarrierName,
                WeightKg = dto.WeightKg
            };

            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/track/{shipment.TrackingNumber}", shipment.ToDto());
        });
    }
}

