@page "/track"
@rendermode InteractiveAuto
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>
<p class="text-muted">Enter your tracking number to see the current status and estimated delivery.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="e.g. TRK-20260501-001"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning" role="alert">
        <strong>Not Found:</strong> @errorMessage
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@shipment.TrackingNumber</h5>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                        <dt>Carrier</dt>
                        <dd>@shipment.CarrierName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                        <dt>Weight</dt>
                        <dd>@shipment.WeightKg kg</dd>
                    </dl>
                </div>
            </div>

            @* Status timeline *@
            <h6 class="mt-3">Shipment Progress</h6>
            <div class="progress" style="height: 25px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0"
                     aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                errorMessage = "No shipment found with that tracking number. Please check and try again.";
            }
        }
        catch
        {
            errorMessage = "Unable to reach the server. Please try again later.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-light text-dark"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

@page "/dispatcher"
@rendermode InteractiveAuto
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Dispatcher Dashboard</h2>
<p class="text-muted">Manage and monitor all shipments.</p>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search tracking #, destination, recipient..."
               @bind="searchTerm" @bind:event="oninput" @onkeydown="HandleSearchKeyDown" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter" @bind:after="LoadShipments">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-outline-primary w-100" @onclick="LoadShipments">
            <span class="bi bi-arrow-clockwise"></span> Refresh
        </button>
    </div>
    <div class="col-md-3 text-end">
        <button class="btn btn-success" @onclick="ToggleNewShipmentForm">
            + New Shipment
        </button>
    </div>
</div>

@if (showNewForm)
{
    <div class="card mb-4">
        <div class="card-header">Create New Shipment</div>
        <div class="card-body">
            <EditForm Model="newShipment" OnValidSubmit="CreateShipment" FormName="NewShipmentForm">
                <DataAnnotationsValidator />
                <div class="row g-3">
                    <div class="col-md-4">
                        <label class="form-label">Tracking Number</label>
                        <InputText class="form-control" @bind-Value="newShipment.TrackingNumber" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Origin</label>
                        <InputText class="form-control" @bind-Value="newShipment.Origin" />
                    </div>
                    <div class="col-md-4">
                        <label class="form-label">Destination</label>
                        <InputText class="form-control" @bind-Value="newShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Recipient</label>
                        <InputText class="form-control" @bind-Value="newShipment.RecipientName" />
                    </div>
                    <div class="col-md-3">
                        <label class="form-label">Carrier</label>
                        <InputText class="form-control" @bind-Value="newShipment.CarrierName" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Weight (kg)</label>
                        <InputNumber class="form-control" @bind-Value="newShipment.WeightKg" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Ship Date</label>
                        <InputDate class="form-control" @bind-Value="newShipment.ShippedDate" />
                    </div>
                    <div class="col-md-2">
                        <label class="form-label">Est. Delivery</label>
                        <InputDate class="form-control" @bind-Value="newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mt-3">
                    <button type="submit" class="btn btn-primary me-2">Create</button>
                    <button type="button" class="btn btn-secondary" @onclick="ToggleNewShipmentForm">Cancel</button>
                </div>
            </EditForm>
        </div>
    </div>
}

@if (isLoading)
{
    <div class="text-center my-4">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (shipments is not null)
{
