                }
                Track
            </button>
        </div>
    </div>
</div>

@if (errorMessage is not null)
{
    <div class="alert alert-warning" role="alert">
        <strong>Not Found:</strong> @errorMessage
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@shipment.TrackingNumber</h5>
            <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@shipment.Status</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>
                        <dt>Carrier</dt>
                        <dd>@shipment.CarrierName</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold text-primary">@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</dd>
                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</dd>
                        }
                        <dt>Weight</dt>
                        <dd>@shipment.WeightKg kg</dd>
                    </dl>
                </div>
            </div>

            @* Status timeline *@
            <h6 class="mt-3">Shipment Progress</h6>
            <div class="progress" style="height: 25px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar"
                     style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)"
                     aria-valuemin="0"
                     aria-valuemax="100">
                    @shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private string? errorMessage;
    private bool isLoading;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        shipment = null;

        try
        {
            var response = await Http.GetAsync($"/api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else
            {
                errorMessage = "No shipment found with that tracking number. Please check and try again.";
            }
        }
        catch
        {
            errorMessage = "Unable to reach the server. Please try again later.";
        }
        finally
        {
            isLoading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info text-dark",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        ShipmentStatus.PickedUp => "bg-secondary",
        _ => "bg-light text-dark"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-primary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        ShipmentStatus.Returned => 100,
        _ => 0
    };
}

